final:
module gray_code_counter(
  input clk,
  input rst_n,
  output reg [3:0] gray
);

  reg [3:0] counter_value;

  always @(posedge clk or negedge rst_n) begin
    if (~rst_n) begin
      counter_value <= 4'b0;
      gray <= 4'b0;
    end
    else begin
      counter_value <= counter_value + 1;
      gray <= counter_value ^ (counter_value >> 1);
    end
  end

endmodule
